const texto = $json.output || "";

// 1. Extraer links de Drive
const matches = [...texto.matchAll(/https?:\/\/[^\s)]+/g)];
const links = matches.map(m => m[0]);

const extraerIdDrive = (url) => {
    if (!url) return null;
    const match = url.match(/(?:\/d\/|id=)([a-zA-Z0-9_-]{25,})/);
    return match ? match[1] : null;
};

const convertirDirecto = (id) => {
    if (!id) return null;
    return `https://drive.google.com/uc?export=view&id=${id}`;
};

const id1 = extraerIdDrive(links[0]);
const id2 = extraerIdDrive(links[1]);

// 2. RESCATE DEL NÚMERO (JID)
// Buscamos el JID del cliente para que no se pierda
const remoteJid_final = $node["Webhook Evolution API1"].json.body.data.key.remoteJid;

return {
    tieneFotos: !!id1,
    foto1: convertirDirecto(id1),
    foto2: convertirDirecto(id2),
    remoteJid_fotos: remoteJid_final // Pasamos el número a la siguiente etapa
};

const item = $input.item.json;
let textoIA = item.output || "";

// 1. Identificamos la etiqueta interna para el Switch
