if (textoIA.includes("#VENTA_ESPECIALIZADA") || textoIA.includes("#VENTA")) etiqueta = "VENTA_ESPECIALIZADA";
else if (textoIA.includes("#BODEGA")) etiqueta = "BODEGA";
else if (textoIA.includes("#SOPORTE")) etiqueta = "SOPORTE";
else if (textoIA.includes("#FLUJO_NORMAL")) etiqueta = "FLUJO_NORMAL";

// 2. Limpiamos TODO lo que el cliente NO debe ver
let respuestaLimpia = textoIA
    .replace(/#PRODUCTO:.*$/gi, "") 
    .replace(/#VENTA_ESPECIALIZADA|#VENTA|#BODEGA|#SOPORTE|#FLUJO_NORMAL/gi, "")
    .replace(/https:\/\/drive\.google\.com\/[^\s\n]+/gi, "") // Borra links de Drive alucinados
    .replace(/\[LINKS:.*?\]/gi, "") 
    .trim();

return {
    ...item,
    respuesta_cliente: respuestaLimpia,
    etiqueta_interna: etiqueta
};
return {
