const items = $input.all();
const newItems = [];

for (const item of items) {
    let textoOriginal = (item.json.output || item.json.respuesta_cliente || "").toString();

    // Identificar alertas para Ferni
    const esPedidoFinal = textoOriginal.includes("#PEDIDO_LISTO") || textoOriginal.includes("#PEDIDO_CONFIRMADO");
    const esSoporte = textoOriginal.includes("#SOPORTE");
    const esVenta = textoOriginal.includes("#VENTA");

    // Regresamos a la regla de solo notificar lo importante:
    const enviarNotificacion = esPedidoFinal || esSoporte || esVenta; 

    // Limpieza de etiquetas que el cliente no debe ver (Rescatando links)
    let textoLimpio = textoOriginal
        .replace(/#PEDIDO_LISTO|#PEDIDO_CONFIRMADO|#VENTA_PROCESO|#VENTA|#BODEGA|#SOPORTE|#REVISAR_TECNICO|#TRANSFERENCIA|#VENTA_ESPECIALIZADA|#FLUJO_NORMAL/gi, "")
        // Limpieza de links: Convierte [Catálogo](link) en texto plano clickeable
        .replace(/\[Catálogo\]\((https?:\/\/[^\s\)]+)\)/gi, "Catálogo: $1")
        // Elimina el residuo [Foto]() ya que la imagen se envía por aparte
        .replace(/\[Foto\]\(\)/gi, "")
        // Limpia otros formatos Markdown de links si existieran para que sean clickeables
        .replace(/\[.*?\]\((https?:\/\/[^\s\)]+)\)/gi, "$1")
        .replace(/\n\s*\n/g, "\n\n")
        .trim();

    // RESCATE CRÍTICO DEL NÚMERO (JID)
    let remoteJid_final = item.json.remoteJid || 
                         item.json.body?.data?.key?.remoteJid || 
                         ( ( $node["Webhook Evolution API1"] ) ? $node["Webhook Evolution API1"].json.body.data.key.remoteJid : null );

    newItems.push({
        json: {
            ...item.json,
            texto_limpio: textoLimpio,
            remoteJid_final: remoteJid_final,
            notificar_vip: enviarNotificacion,
            aviso_ferni: esPedidoFinal ? "🚀 *PEDIDO LISTO*" : 
                         esSoporte ? "🔧 *SOPORTE*" : 
                         esVenta ? "💰 *VENTA*" : "" 
        }
    });
}
return newItems;

const items = $input.all();
const newItems = [];

for (const item of items) {
    // 1. Buscamos el mensaje del cliente con prioridad en el nodo MERGE
    let mensajeCliente = "";

    try {
        // Intentamos jalarlo directamente del nodo Merge
        mensajeCliente = $node["Merge"].json.mensaje || item.json.mensaje;
    } catch (e) {
        mensajeCliente = item.json.mensaje || "Mensaje no recuperado";
    }

    // 2. Buscamos qué fue lo último que dijo la Recepcionista
    // Esto suele venir del nodo 'recepcionista' o 'LIMPIEZA Y ESTADOS'
    let respuestaIA = item.json.output || item.json.respuesta_cliente || "";

    newItems.push({
        json: {
            ...item.json,
            resumen_cliente: mensajeCliente, 
            resumen_ia: respuestaIA,
            remoteJid_final: item.json.remoteJid_final || item.json.body?.data?.key?.remoteJid
        }
    });
}

return newItems;

const item = $input.item.json;

// OpenAI image node can return content as string, array, or nested object
let texto = "";
if (typeof item.content === 'string') {
  texto = item.content;
} else if (Array.isArray(item.content)) {
  texto = item.content.map(c => c.text || c.content || JSON.stringify(c)).join('\n');
} else if (item.text) {
  texto = item.text;
} else if (item.message) {
  texto = item.message;
} else {
  texto = JSON.stringify(item);
}

const remoteJid = $node["Preparar Datos Luis"].json.remoteJid_final;

if (!texto || texto.includes("NO_FACTURA")) {
  return {
    json: {
      es_factura: false,
      mensaje: "No pude leer una factura en esa imagen 🤔 Probá mandarla con mejor luz o más enfocada 📸",
      remoteJid_final: remoteJid,
      tipo_entrada: "respuesta_directa"
    }
  };
}

const extraer = (campo) => {
  const match = texto.match(new RegExp(campo + ": (.+)"));
  return match ? match[1].trim() : "DESCONOCIDO";
};

const descripcion = extraer("DESCRIPCION");
const montoRaw = extraer("MONTO").replace(/[^0-9.]/g, "");
const monto = parseFloat(montoRaw) || 0;
const proveedor = extraer("PROVEEDOR");
const fecha = extraer("FECHA");

// Validate we got actual data
if (descripcion === "DESCONOCIDO" && monto === 0) {
  return {
    json: {
      es_factura: false,
      mensaje: "No logré extraer los datos de la factura 🤔 Probá con mejor iluminación o más cerca 📸",
      remoteJid_final: remoteJid,
      tipo_entrada: "respuesta_directa"
    }
  };
}

return {
  json: {
    es_factura: true,
    descripcion_factura: descripcion,
