pendientes.forEach(item => {
  const j = item.json;
  const monto = parseFloat(j.Monto) || 0;
  total += monto;

  if (j.Descripcion && j.Descripcion.startsWith('BODEGA PENDIENTE:')) {
    soloBodega.push(`   📦 ${j.Descripcion.replace('BODEGA PENDIENTE:', '').trim()}`);
  } else {
    conMonto.push(`   • ${j.Descripcion || 'Sin descripción'} → Q${monto.toFixed(2)}`);
  }
});

