  desglose += conMonto.join('\n');
}
if (soloBodega.length > 0) {
  desglose += (desglose ? '\n\n📦 *Pendientes de bodega:*\n' : '📦 *Pendientes de bodega:*\n');
  desglose += soloBodega.join('\n');
}

